import{_ as a,o as i,c as t,ai as r,aj as n}from"./chunks/framework.DG6aArJf.js";const u=JSON.parse('{"title":"DOM Helpers – Approach & Philosophy","description":"","frontmatter":{},"headers":[],"relativePath":"creator/approach-and-philosophy.md","filePath":"creator/approach-and-philosophy.md"}'),s={name:"creator/approach-and-philosophy.md"};function o(l,e,p,h,d,c){return i(),t("div",null,[...e[0]||(e[0]=[r('<p><a href="https://github.com/sponsors/giovanni1707" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/Sponsor-%F0%9F%92%96-pink" alt="Sponsor"></a></p><p><a href="https://paypal.me/GiovanniSylvain" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/Sponsor-PayPal-blue?logo=paypal" alt="Sponsor"></a></p><h1 id="dom-helpers-–-approach-philosophy" tabindex="-1">DOM Helpers – Approach &amp; Philosophy <a class="header-anchor" href="#dom-helpers-–-approach-philosophy" aria-label="Permalink to “DOM Helpers – Approach &amp; Philosophy”">​</a></h1><div class="creator"><img src="'+n+'" alt="Giovanni Marianne" class="creator-photo"><div class="creator-info"><p><strong>Giovanni Marianne</strong></p><p>Creator of DOM Helpers Library</p></div></div><h2 id="a-library-that-enhances-javascript-not-replaces-it" tabindex="-1">A Library That Enhances JavaScript, Not Replaces It <a class="header-anchor" href="#a-library-that-enhances-javascript-not-replaces-it" aria-label="Permalink to “A Library That Enhances JavaScript, Not Replaces It”">​</a></h2><p><strong>DOM Helpers is a JavaScript library built to enhance vanilla JavaScript, not replace it.</strong></p><p>It adds superpowers to the JavaScript you already know, allowing you to write code that is:</p><ul><li>Clean and expressive</li><li>Easy to read and reason about</li><li>Maintainable and expandable</li><li>Ready for real-world production use</li></ul><p>DOM Helpers acts as a <strong>bridge between imperative and declarative programming</strong>, allowing you to express intent clearly while maintaining full control over what&#39;s happening under the hood.</p><h2 id="declarative-expression-imperative-control" tabindex="-1">Declarative Expression, Imperative Control <a class="header-anchor" href="#declarative-expression-imperative-control" aria-label="Permalink to “Declarative Expression, Imperative Control”">​</a></h2><p>JavaScript is naturally imperative—you tell the computer <em>how</em> to do things:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">element.textContent </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Hello&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>DOM Helpers keeps that control but lets you <strong>express your intent declaratively</strong>:</p><ul><li>You <strong>say what you want</strong></li><li>JavaScript still <strong>does exactly how it works</strong></li></ul><p>This balance is intentional. DOM Helpers does <strong>not introduce magic abstractions</strong> that hide behavior. Instead, it makes JavaScript <strong>more enjoyable to write</strong>, while remaining transparent and predictable.</p><p>You write imperative JavaScript logic, but in a way that:</p><ul><li>Clearly communicates your intent</li><li>Avoids unnecessary boilerplate</li><li>Improves clarity and maintainability</li></ul><h2 id="you-re-not-learning-a-new-language" tabindex="-1">You&#39;re Not Learning a New Language <a class="header-anchor" href="#you-re-not-learning-a-new-language" aria-label="Permalink to “You&#39;re Not Learning a New Language”">​</a></h2><p>One of the core philosophies of DOM Helpers is simple:</p><blockquote><p><strong>When you learn DOM Helpers, you are learning JavaScript.</strong></p></blockquote><p>There is:</p><ul><li>No custom syntax</li><li>No special DSL</li><li>No hidden runtime rules</li></ul><p>Everything you use in DOM Helpers is <strong>built on top of real JavaScript concepts</strong>:</p><ul><li>DOM APIs</li><li>Arrays and objects</li><li>Functions and events</li><li>Native browser behavior</li></ul><p>If you already know basic JavaScript, <strong>DOM Helpers feels like candy 🍬</strong>—familiar, but more powerful.</p><p>That&#39;s why JavaScript lovers love it.</p><h2 id="superpower-not-reinvention" tabindex="-1">Superpower, Not Reinvention <a class="header-anchor" href="#superpower-not-reinvention" aria-label="Permalink to “Superpower, Not Reinvention”">​</a></h2><p>DOM Helpers doesn&#39;t reinvent JavaScript methods—it <strong>extends them with meaningful capabilities</strong>.</p><p>For example:</p><p>In plain JavaScript, <code>push()</code> only mutates an array.</p><p>In <strong>DOM Helpers Reactive</strong>, <code>push()</code> gains an extra superpower:</p><ul><li>It mutates the array</li><li><strong>It triggers reactivity automatically</strong></li></ul><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">state.items.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">push</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;New item&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// UI updates automatically</span></span></code></pre></div><p>This is something <strong>plain JavaScript cannot do by itself</strong>, but DOM Helpers adds it <strong>without breaking JavaScript&#39;s mental model</strong>.</p><p>Everything still behaves like JavaScript—just enhanced.</p><h2 id="transparent-by-design" tabindex="-1">Transparent by Design <a class="header-anchor" href="#transparent-by-design" aria-label="Permalink to “Transparent by Design”">​</a></h2><p>Many modern frameworks internally use native APIs like <code>textContent</code>, <code>setAttribute</code>, or <code>appendChild</code>—but they <strong>hide these details behind heavy abstractions</strong>.</p><p>As a result, many developers:</p><ul><li>Use frameworks for years</li><li>Without knowing the actual DOM APIs being used</li></ul><p>DOM Helpers takes the opposite approach.</p><p>It is <strong>transparent</strong>.</p><p>You always know:</p><ul><li>What JavaScript property is being used</li><li>What DOM method is being called</li><li>Why something updates</li></ul><p>You don&#39;t see magic—you see JavaScript.</p><p>This strengthens your fundamentals instead of replacing them with &quot;magic&quot;. You build real understanding and become a better JavaScript developer.</p><h2 id="familiar-naming-intentional-design" tabindex="-1">Familiar Naming, Intentional Design <a class="header-anchor" href="#familiar-naming-intentional-design" aria-label="Permalink to “Familiar Naming, Intentional Design”">​</a></h2><p>DOM Helpers uses <strong>method names and patterns inspired by well-known frameworks</strong>.</p><p>This is a <strong>deliberate and thoughtful design choice</strong>, not imitation.</p><h3 id="why" tabindex="-1">Why? <a class="header-anchor" href="#why" aria-label="Permalink to “Why?”">​</a></h3><ul><li>If you already know popular frameworks, DOM Helpers feels easy to adopt</li><li>If you learn DOM Helpers first, transitioning to those frameworks becomes easier later</li></ul><p>You learn <strong>the ideas behind the patterns</strong>, but in a simpler, more explicit way.</p><p>DOM Helpers teaches <em>approach and thinking</em>, not just syntax.</p><h3 id="documentation-that-feels-familiar" tabindex="-1">Documentation That Feels Familiar <a class="header-anchor" href="#documentation-that-feels-familiar" aria-label="Permalink to “Documentation That Feels Familiar”">​</a></h3><p>The documentation itself follows a <strong>framework-style structure</strong>, similar to Vue.js documentation.</p><p>This provides:</p><ul><li>Easy navigation</li><li>Familiar learning flow</li><li>Immediate comfort for developers from any ecosystem</li></ul><p>If you&#39;ve used modern framework docs before, you&#39;ll recognize the structure instantly—and that&#39;s intentional.</p><h2 id="not-competing-with-frameworks" tabindex="-1">Not Competing With Frameworks <a class="header-anchor" href="#not-competing-with-frameworks" aria-label="Permalink to “Not Competing With Frameworks”">​</a></h2><p>DOM Helpers is <strong>not trying to replace frameworks</strong>.</p><p>That is not the goal.</p><p>The philosophy is different:</p><ul><li>Solve real developer pain points</li><li>Bring developers closer to native APIs</li><li>Strengthen JavaScript fundamentals</li><li>Enable production-ready applications with minimal dependencies</li></ul><p>DOM Helpers complements vanilla JavaScript and exists to <strong>superpower the indispensable skill</strong> that drives both frontend and backend development.</p><p>JavaScript is indispensable. DOM Helpers makes it better.</p><h2 id="in-summary" tabindex="-1">In Summary <a class="header-anchor" href="#in-summary" aria-label="Permalink to “In Summary”">​</a></h2><p>DOM Helpers is:</p><ul><li>A bridge between declarative and imperative programming</li><li>A superpower for vanilla JavaScript</li><li>Transparent, explicit, and predictable</li><li>Familiar yet powerful</li><li>Designed for clarity, maintainability, and production use</li></ul><p><strong>If you love JavaScript</strong>, DOM Helpers is built for you.</p><p><strong>If you&#39;re learning JavaScript</strong>, DOM Helpers helps you learn it better.</p>',69)])])}const m=a(s,[["render",o]]);export{u as __pageData,m as default};
